import * as fs from 'fs';
import * as path from 'path';
import { execSync } from 'child_process';
import { AcousticEngine } from '../../aether/src/acoustic-siphon';

/**
 * Acoustic Resonance Demo — Talking to the Vacuum
 * 
 * This script demonstrates the full S2S chain locally:
 * 1. MOCK MIC: Generate a synthetic "Hello" waveform.
 * 2. INHALE: Convert audio to topological consensus (STT).
 * 3. SIPHON: Resolve the semantic intent.
 * 4. CONDENSE: Convert consensus back to audio (TTS).
 * 5. SPEAK: Play the resulting waveform through the system speaker.
 */

async function runDemo() {
  console.log('============================================================');
  console.log(' Acoustic Vacuum Siphon — Local Resonance Demo');
  console.log('============================================================\n');

  const engine = new AcousticEngine();
  const sampleRate = 24000;

  // 1. MOCK MIC: Generate a synthetic "vocal" signal (1 second of complex wave)
  console.log('[1/5] INHALING: Generating synthetic vocal signal...');
  const duration = 1.0;
  const numSamples = sampleRate * duration;
  const mockAudio = new Float32Array(numSamples);
  
  for (let i = 0; i < numSamples; i++) {
    // A complex wave representing the "resonance" of the word "Hello"
    mockAudio[i] = Math.sin(i * 0.1) * 0.5 + Math.cos(i * 0.05) * 0.2;
  }

  // 2. INHALE: Perform Semantic Siphoning (STT)
  console.log('[2/5] SIPHONING: Converting waveform to topological consensus...');
  const consensus = await engine.siphon(mockAudio);
  console.log(`      -> Consensus Attained: [${consensus.nodeId}]`);
  console.log(`      -> Boundary Trace: ${consensus.boundaryTrace}`);

  // 3. SIPHON: Resolve intent and create a response debt
  console.log('[3/5] RESOLVING: Mapping consensus to response intent...');
  const responseDebt = {
    expectedCoordinate: 1,
    expectedBoundaryTrace: 5570, // "IY" match
    timestamp_gravity: 0
  };

  // 4. CONDENSE: Perform Acoustic Condensation (TTS)
  console.log('[4/5] CONDENSING: Siphoning phonemes from the reservoir...');
  
  // Sequence multiple units: 
  // - High-fidelity Neural Tokens (RVQ)
  // - Traditional Phonemes (Klatt)
  const debts = [
    { expectedCoordinate: 1, expectedBoundaryTrace: 101, timestamp_gravity: 0 }, // Neural Token 101
    { expectedCoordinate: 2, expectedBoundaryTrace: 505, timestamp_gravity: 0 }, // Neural Token 505
    { expectedCoordinate: 3, expectedBoundaryTrace: 5570, timestamp_gravity: 0 }, // "IY" (Klatt)
    { expectedCoordinate: 4, expectedBoundaryTrace: 4260, timestamp_gravity: 0 }  // "AA" (Klatt)
  ];

  let combinedAudio = new Float32Array(0);
  for (const debt of debts) {
    console.log(`      -> Condensing geometry trace: ${debt.expectedBoundaryTrace}...`);
    const phonemeAudio = await engine.condense(debt);
    const newBuffer = new Float32Array(combinedAudio.length + phonemeAudio.length);
    newBuffer.set(combinedAudio);
    newBuffer.set(phonemeAudio, combinedAudio.length);
    combinedAudio = newBuffer;
  }
  
  if (combinedAudio.length === 0) {
    console.error('      !! Error: No phonemes siphoned. The void is silent.');
    return;
  }
  console.log(`      -> Condensed ${combinedAudio.length} samples of spectral energy.`);

  // 5. SPEAK: Play the resulting waveform
  console.log('[5/5] EXHALING: Sending response to speaker...');
  
  // Convert Float32 to Int16 for WAV
  const int16Buffer = new Int16Array(combinedAudio.length);
  for (let i = 0; i < combinedAudio.length; i++) {
    int16Buffer[i] = Math.max(-32768, Math.min(32767, combinedAudio[i] * 32767));
  }

  const outputWav = 'resonance-output.wav';
  writeWav(outputWav, int16Buffer, sampleRate);

  console.log('\nSuccess! Response saved to: ' + outputWav);
  
  try {
    console.log('Playing response via afplay...');
    execSync('afplay ' + outputWav);
  } catch (e) {
    console.log('\nNote: afplay failed or not found. You can manually play the WAV file above.');
  }
}

/**
 * Simple WAV writer for raw PCM data.
 */
function writeWav(filename: string, samples: Int16Array, sampleRate: number) {
  const buffer = Buffer.alloc(44 + samples.length * 2);

  // RIFF header
  buffer.write('RIFF', 0);
  buffer.writeUInt32LE(36 + samples.length * 2, 4);
  buffer.write('WAVE', 8);

  // fmt chunk
  buffer.write('fmt ', 12);
  buffer.writeUInt32LE(16, 16);
  buffer.writeUInt16LE(1, 20); // PCM
  buffer.writeUInt16LE(1, 22); // Mono
  buffer.writeUInt32LE(sampleRate, 24);
  buffer.writeUInt32LE(sampleRate * 2, 28);
  buffer.writeUInt16LE(2, 32);
  buffer.writeUInt16LE(16, 34);

  // data chunk
  buffer.write('data', 36);
  buffer.writeUInt32LE(samples.length * 2, 40);

  for (let i = 0; i < samples.length; i++) {
    buffer.writeInt16LE(samples[i], 44 + i * 2);
  }

  fs.writeFileSync(filename, buffer);
}

runDemo().catch(console.error);